async (page) => {
  const click = (x, y) => page.evaluate(({x, y}) => {
    document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true }));
  }, {x, y});

  // Navigate to Forester: go northeast via bridge
  // First go north-east past the river
  await click(900, 80);
  await page.waitForTimeout(3000);
  await click(900, 80);
  await page.waitForTimeout(3000);
  await click(900, 150);
  await page.waitForTimeout(3000);

  const checkDist = () => page.evaluate(() => {
    const npc = window.__latestGameState.nearby_entities.find(e => e.name === 'Forester');
    return {dist: npc?.distance, pos: window.__latestGameState.player_position};
  });

  let state = await checkDist();

  // Keep going until close
  for (let i = 0; i < 10; i++) {
    if (state.dist && state.dist <= 3) break;
    await click(850, 100);
    await page.waitForTimeout(2500);
    state = await checkDist();
  }

  await page.screenshot({ path: '/tmp/kaetram_agent_2/state/screenshot.png', type: 'png' });
  return JSON.stringify(state);
}

async (page) => {
  // Click the Forester with fresh coords
  const result = await page.evaluate(() => {
    const game = window.game;
    const camera = game.renderer.camera;
    const sx = (216 * 16 - camera.x) * 3;
    const sy = (114 * 16 - camera.y) * 3;
    document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: sx, clientY: sy, bubbles: true }));
    return { sx, sy };
  });
  await page.waitForTimeout(1500);

  // Check dialogue and quest button state
  const uiState = await page.evaluate(() => {
    const questBtn = document.getElementById('quest-button');
    // Look for any dialogue containers
    const dialogues = Array.from(document.querySelectorAll('[id*="dialogue"], [class*="dialogue"], [class*="bubble"], [class*="chat"]'))
      .map(el => ({ id: el.id, cls: el.className, text: el.textContent.trim().slice(0, 100), visible: el.offsetParent !== null }));
    return {
      click: result,
      questBtn: questBtn ? { text: questBtn.textContent.trim(), visible: questBtn.offsetParent !== null } : null,
      dialogues: dialogues.filter(d => d.text.length > 0).slice(0, 5)
    };
  });

  await page.screenshot({ path: '/tmp/kaetram_agent_2/state/screenshot.png', type: 'png' });
  return JSON.stringify(uiState);
}

async (page) => {
  // Chop the Oak tree at (206, 118) with repeated clicks
  const chopTree = (tx, ty) => page.evaluate(({tx, ty}) => {
    const game = window.game;
    const camera = game.renderer.camera;
    const sx = (tx * 16 - camera.x) * 3;
    const sy = (ty * 16 - camera.y) * 3;
    document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: sx, clientY: sy, bubbles: true }));
    return { sx, sy };
  }, {tx, ty});

  // Chop Oak at (206, 118)
  await chopTree(206, 118);
  await page.waitForTimeout(8000);

  let invCount = await page.evaluate(() => window.__latestGameState.inventory.length);
  let logCount = await page.evaluate(() => window.__latestGameState.inventory.filter(i => i.key === 'logs').length);

  // Try another tree if not enough logs
  if (logCount < 8) {
    await chopTree(214, 118);
    await page.waitForTimeout(8000);
    logCount = await page.evaluate(() => window.__latestGameState.inventory.filter(i => i.key === 'logs').length);
