async (page) => {
  // Walk north step by step - clicking near top of visible area
  const walkStep = async () => {
    const pos = await page.evaluate(() => window.__latestGameState.player_position);
    // Click 6 tiles north and 5 tiles east of player (within viewport)
    await page.evaluate(() => {
      const game = window.game;
      const camera = game.renderer.camera;
      const p = window.__latestGameState.player_position;
      // Target: 6 tiles north, 4 tiles east (safe on-screen values)
      const targetX = Math.min(p.x + 4, 216);
      const targetY = Math.max(p.y - 6, 114);
      const sx = (targetX * 16 - camera.x) * 3;
      const sy = (targetY * 16 - camera.y) * 3;
      document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: sx, clientY: sy, bubbles: true }));
      return { sx, sy, targetX, targetY };
    });
    await page.waitForTimeout(3500);
    return pos;
  };

  // Walk until within distance 5 of Forester at (216, 114)
  let attempts = 0;
  while (attempts < 15) {
    const state = await page.evaluate(() => {
      const s = window.__latestGameState;
      const f = s.nearby_entities.find(e => e.name === 'Forester');
      return { pos: s.player_position, dist: f ? f.distance : 999 };
    });
    if (state.dist <= 5) break;
    await walkStep();
    attempts++;
  }

  const finalState = await page.evaluate(() => {
    const s = window.__latestGameState;
    const f = s.nearby_entities.find(e => e.name === 'Forester');
    return { pos: s.player_position, dist: f ? f.distance : 999 };
  });

  return JSON.stringify(finalState);
}

