async (page) => {
  // Walk toward Blueberry Bush at (184, 189) - south and west
  // First walk south in small steps
  const walkSouth = () => page.evaluate(() => {
    const game = window.game;
    const camera = game.renderer.camera;
    const p = window.__latestGameState.player_position;
    // Click 5 tiles south, 2 west (within viewport)
    const tx = Math.max(p.x - 2, 184);
    const ty = Math.min(p.y + 5, 189);
    const sx = (tx * 16 - camera.x) * 3;
    const sy = (ty * 16 - camera.y) * 3;
    document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: sx, clientY: sy, bubbles: true }));
    return { tx, ty };
  });

  // Walk in steps until near bush
  for (let i = 0; i < 4; i++) {
    const r = await walkSouth();
    await page.waitForTimeout(4000);
    const pos = await page.evaluate(() => window.__latestGameState.player_position);
    if (pos.y >= 187 && Math.abs(pos.x - 184) <= 2) break;
  }

  // Check HP and nearby items
  const state = await page.evaluate(() => {
    const s = window.__latestGameState;
    const bushes = s.nearby_entities.filter(e => e.type === 12 && e.distance < 10);
    const drops = s.nearby_entities.filter(e => e.type === 4);
    return { hp: s.player_stats.hp, pos: s.player_position, bushes, drops };
  });
  return JSON.stringify(state);
}

