async (page) => {
  // Navigate north by clicking at the top of screen repeatedly
  // This moves toward visible top edge, moving character north

  let pos = await page.evaluate(() => window.__latestGameState.player_position);
  let hp = await page.evaluate(() => window.__latestGameState.player_stats.hp);

  // Keep clicking upper-right to move toward Forester at (216, 114)
  let steps = 0;
  while (pos.y > 120 && steps < 20 && hp > 20) {
    // Click toward upper-right area of screen (northeast direction)
    const clickX = pos.x < 210 ? 900 : 640; // if west of target, click northeast; else north
    await page.evaluate(({cx}) => {
      document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: cx, clientY: 60, bubbles: true }));
    }, {cx: clickX});
    await page.waitForTimeout(4000);

    const newState = await page.evaluate(() => ({
      pos: window.__latestGameState.player_position,
      hp: window.__latestGameState.player_stats.hp,
      foresterDist: (() => {
        const f = window.__latestGameState.nearby_entities.find(e => e.name === 'Forester');
        return f ? f.distance : 999;
      })()
    }));
    pos = newState.pos;
    hp = newState.hp;
    steps++;

    if (newState.foresterDist <= 5) break;
  }

  const finalState = await page.evaluate(() => {
    const s = window.__latestGameState;
    const f = s.nearby_entities.find(e => e.name === 'Forester');
    return { pos: s.player_position, hp: s.player_stats.hp, foresterDist: f ? f.distance : 999 };
  });

  return JSON.stringify(finalState);
}

