async (page) => {
  // Get exact VG screen position and click
  const vgPos = await page.evaluate(() => {
    const camera = window.game.renderer.camera;
    return {
      sx: (136 * 16 - camera.x) * 3,
      sy: (146 * 16 - camera.y) * 3
    };
  });
  console.log('VG pos:', JSON.stringify(vgPos));

  // Click on Village Girl
  await page.evaluate(({x, y}) => {
    document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true }));
  }, {x: vgPos.sx, y: Math.max(30, vgPos.sy)});

  await page.waitForTimeout(2000);

  const dialogue = await page.evaluate(() => {
    const b = document.querySelector('.bubble-text, .dialogue, [class*="bubble"]');
    const qBtn = document.getElementById('quest-button');
    return { 
      text: b?.textContent?.trim(),
      questBtnVisible: qBtn ? window.getComputedStyle(qBtn).display !== 'none' : false
    };
  });

  await page.screenshot({ path: '/tmp/kaetram_agent_2/state/screenshot.png', type: 'png' });
  return JSON.stringify({ vgPos, dialogue });
}

