async (page) => {
  await page.evaluate(() => {
    window.game.menu.warp.show();
    setTimeout(() => document.getElementById('warp0').click(), 500);
  });
  await page.waitForTimeout(4000);

  const goTo = async (tx, ty, maxWait = 15) => {
    await page.evaluate(({tx, ty}) => window.game.player.go(tx, ty), {tx, ty});
    let lastPos = null;
    for (let i = 0; i < maxWait; i++) {
      await page.waitForTimeout(1000);
      const pos = await page.evaluate(() => window.__latestGameState?.player_position);
      if (JSON.stringify(pos) === JSON.stringify(lastPos)) return pos;
      lastPos = pos;
    }
    return await page.evaluate(() => window.__latestGameState?.player_position);
  };

  // Go south from Mudwich to find beach
  let pos = await goTo(199, 185);
  console.log('South Mudwich:', JSON.stringify(pos));

  pos = await goTo(210, 200);
  console.log('SE:', JSON.stringify(pos));

  await page.screenshot({ path: '/tmp/kaetram_agent_2/state/screenshot.png', type: 'png' });

  const entities = await page.evaluate(() => {
    const gs = window.__latestGameState;
    return (gs?.nearby_entities || []).slice(0, 15).map(e => ({ name: e.name, type: e.type, x: e.x, y: e.y, dist: e.distance, quest_npc: e.quest_npc }));
  });

  return JSON.stringify({ pos, entities });
}

