async (page) => {
  // Pick up visible drops
  await page.evaluate(() => {
    const gs = window.__latestGameState;
    const camera = window.game.renderer.camera;
    for (const drop of (gs?.nearby_entities || []).filter(e => e.type === 4)) {
      const sx = (drop.x * 16 - camera.x) * 3;
      const sy = (drop.y * 16 - camera.y) * 3;
      if (sx >= 48 && sx <= 1232 && sy >= 48 && sy <= 672) {
        document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: sx, clientY: sy, bubbles: true }));
      }
    }
  });
  await page.waitForTimeout(2000);

  // Navigate to Mudwich for quests
  await page.evaluate(() => window.game.player.go(189, 159));
  await page.waitForTimeout(8000);

  await page.screenshot({ path: '/tmp/kaetram_agent_2/state/screenshot.png', type: 'png' });
  const state = await page.evaluate(() => {
    const gs = window.__latestGameState;
    return {
      pos: gs?.player_position,
      npcs: (gs?.nearby_entities || []).filter(e => e.type === 1).slice(0, 8).map(e => ({name: e.name, dist: e.distance, quest_npc: e.quest_npc, has_achievement: e.has_achievement, cx: e.click_x, cy: e.click_y}))
    };
  });
  return JSON.stringify(state);
}

async (page) => {
  // Check detailed quest info and look for quest NPCs
  const questInfo = await page.evaluate(() => {
    const player = window.game?.player;
    const quests = window.game?.quests;
    const result = {};
    if (quests) {
      for (const [k, q] of Object.entries(quests)) {
        if (q.stage > 0 || k === 'scavenger') {
          result[k] = {
            name: q.name,
            stage: q.stage,
            stageCount: q.stageCount,
            description: q.description,
            // Try to get stage-specific text
            stageText: q.stages?.[q.stage]?.task || q.stages?.[q.stage]?.text || null,
            npc: q.npc || q.stages?.[q.stage]?.npc || null,
            npcs: q.npcs || null
          };
        }
      }
    }
    return result;
  });
  return JSON.stringify(questInfo);
}

