async (page) => {
  const goTo = async (tx, ty, maxWait = 10) => {
    await page.evaluate(({tx, ty}) => window.game.player.go(tx, ty), {tx, ty});
    let lastPos = null;
    for (let i = 0; i < maxWait; i++) {
      await page.waitForTimeout(1000);
      const pos = await page.evaluate(() => window.__latestGameState?.player_position);
      if (pos && pos.x === tx && pos.y === ty) return pos;
      if (JSON.stringify(pos) === JSON.stringify(lastPos)) return pos;
      lastPos = pos;
    }
    return await page.evaluate(() => window.__latestGameState?.player_position);
  };

  // Navigate toward Bubba
  let pos = await goTo(125, 228);
  console.log('pos:', JSON.stringify(pos));

  // Check dist to Bubba
  const bubba = await page.evaluate(() => {
    const gs = window.__latestGameState;
    return (gs?.nearby_entities || []).find(e => e.name === 'Bubba');
  });
  console.log('bubba:', JSON.stringify(bubba));

  // Click Bubba if close enough
  if (bubba && bubba.distance <= 5) {
    await page.evaluate(() => {
      const camera = window.game.renderer.camera;
      const gs = window.__latestGameState;
      const b = (gs?.nearby_entities || []).find(e => e.name === 'Bubba');
      if (b) {
        const sx = (b.x * 16 - camera.x) * 3;
        const sy = (b.y * 16 - camera.y) * 3;
        document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: sx, clientY: sy, bubbles: true }));
      }
    });
    await page.waitForTimeout(2000);
  }

  await page.screenshot({ path: '/tmp/kaetram_agent_2/state/screenshot.png', type: 'png' });
  const state = await page.evaluate(() => {
    const gs = window.__latestGameState;
    const b = (gs?.nearby_entities || []).find(e => e.name === 'Bubba');
    return { pos: gs?.player_position, bubba_dist: b?.distance, bubba_has_ach: b?.has_achievement };
  });
  return JSON.stringify(state);
}

