async (page) => {
  const click = (x, y) => page.evaluate(({x, y}) => {
    document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true }));
  }, {x, y});

  const pos = await page.evaluate(() => window.__latestGameState?.player_position);
  console.log('Current pos:', JSON.stringify(pos));

  // Try the door of the red building - scan around x=120-130, y=107-112 for portals
  const portalScan = await page.evaluate(() => {
    const map = window.game?.map;
    const portals = [];
    // Broader portal scan - try all openings (not just N+EW)
    for (let y = 95; y <= 125; y++) {
      for (let x = 112; x <= 145; x++) {
        const v = map?.grid?.[y]?.[x];
        if (v !== 0) continue;

        const vN = map?.grid?.[y-1]?.[x] ?? 0;
        const vS = map?.grid?.[y+1]?.[x] ?? 0;
        const vW = map?.grid?.[y]?.[x-1] ?? 0;
        const vE = map?.grid?.[y]?.[x+1] ?? 0;

        // Any kind of door-like opening
        const wallCount = [vN, vS, vW, vE].filter(v => v === 1).length;
        if (wallCount >= 2 && wallCount <= 3) {
          portals.push({x, y, N:vN, S:vS, W:vW, E:vE, wallCount});
        }
      }
    }
    return portals.slice(0, 20);
  });

  console.log('Portal scan:', JSON.stringify(portalScan));

  // Click the building door at screen ~(305, 390)
  await click(305, 390);
  await page.waitForTimeout(3000);

  const newPos = await page.evaluate(() => window.__latestGameState?.player_position);
  console.log('After click:', JSON.stringify(newPos));

  await page.screenshot({ path: '/tmp/kaetram_agent_2/state/screenshot.png', type: 'png' });
  return JSON.stringify({pos, newPos, portalScan: portalScan.slice(0, 10)});
}

