  const invBefore = await page.evaluate(() => 
    Array.from(document.getElementById('inventory')?.querySelectorAll('li[data-key]') || [])
      .filter(li => li.dataset.key).map(li => ({key: li.dataset.key, count: li.dataset.count}))
  );

