  const goTo = async (tx, ty, maxWait = 12) => {
    await page.evaluate(({tx, ty}) => window.game.player.go(tx, ty), {tx, ty});
    let lastPos = null;
    for (let i = 0; i < maxWait; i++) {
      await page.waitForTimeout(1000);
      const pos = await page.evaluate(() => window.__latestGameState?.player_position);
      if (pos && pos.x === tx && pos.y === ty) return pos;
      if (JSON.stringify(pos) === JSON.stringify(lastPos)) return pos;
      lastPos = pos;
    }
    return await page.evaluate(() => window.__latestGameState?.player_position);
  };

  // Kill goblins in the way
  for (let i = 0; i < 3; i++) {
    const goblin = await page.evaluate(() => {
      const s = window.__latestGameState;
      return s?.nearby_entities?.find(e => e.name === 'Goblin' && e.on_screen);
    });
    if (!goblin) break;

    await page.evaluate(({x, y}) => {
      document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true }));
    }, { x: goblin.click_x, y: goblin.click_y });
    await page.waitForTimeout(9000);

    const hp = await page.evaluate(() => window.__latestGameState?.player_stats?.hp);
    console.log(`After goblin ${i+1}, hp: ${hp}`);
    if (hp < 30) { console.log('Low HP'); break; }
  }

  // Now navigate to portal at (199, 209)
  let pos = await goTo(199, 209);
  console.log('portal:', JSON.stringify(pos));

  if (pos.y < 207) {
    // Try from south via canvas click
    for (let i = 0; i < 8; i++) {
      await page.evaluate(() => {
        document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: 640, clientY: 580, bubbles: true }));
      });
      await page.waitForTimeout(1500);
      const p = await page.evaluate(() => window.__latestGameState?.player_position);
      if (p?.y >= 207) { pos = p; break; }
    }
  }

  await page.screenshot({ path: '/tmp/kaetram_agent_2/state/screenshot.png', type: 'png' });

  const state = await page.evaluate(() => {
    const s = window.__latestGameState;
    return JSON.stringify({ pos: s?.player_position, stats: s?.player_stats });
  });
  return state;
}

